using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides web search capabilities to the research agent.
/// Uses the Brave Search API when a key is configured; otherwise returns simulated results.
/// </summary>
public sealed class WebSearchTool(IHttpClientFactory httpClientFactory, ILogger<WebSearchTool> logger)
{
    [Description("Search the web for information on a given query. Returns a list of relevant results with titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (default 5)")] int maxResults = 5)
    {
        logger.LogDebug("Web search: \"{Query}\" (max {Max})", query, maxResults);

        var braveApiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");

        if (!string.IsNullOrWhiteSpace(braveApiKey))
        {
            return await SearchBraveAsync(query, maxResults, braveApiKey);
        }

        // Simulated results when no API key is configured
        logger.LogInformation("No BRAVE_API_KEY set — returning simulated search results");
        return JsonSerializer.Serialize(new[]
        {
            new { Title = $"Overview of {query}", Url = $"https://example.com/{Uri.EscapeDataString(query)}", Snippet = $"A comprehensive overview covering the key aspects of {query}, including history, current state, and future outlook." },
            new { Title = $"{query} - Latest Research", Url = $"https://research.example.com/{Uri.EscapeDataString(query)}", Snippet = $"Recent peer-reviewed studies and findings related to {query}. Covers methodology, results, and implications." },
            new { Title = $"Practical Guide to {query}", Url = $"https://guide.example.com/{Uri.EscapeDataString(query)}", Snippet = $"Step-by-step practical guide for understanding and working with {query}. Includes examples and best practices." },
        });
    }

    private async Task<string> SearchBraveAsync(string query, int maxResults, string apiKey)
    {
        using var client = httpClientFactory.CreateClient();
        client.DefaultRequestHeaders.Add("X-Subscription-Token", apiKey);
        client.DefaultRequestHeaders.Add("Accept", "application/json");

        var url = $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={maxResults}";
        var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());

        var results = doc.RootElement
            .GetProperty("web")
            .GetProperty("results")
            .EnumerateArray()
            .Take(maxResults)
            .Select(r => new
            {
                Title = r.GetProperty("title").GetString(),
                Url = r.GetProperty("url").GetString(),
                Snippet = r.TryGetProperty("description", out var d) ? d.GetString() : "",
            })
            .ToList();

        logger.LogInformation("Brave search returned {Count} results for \"{Query}\"", results.Count, query);
        return JsonSerializer.Serialize(results);
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides note-taking capabilities so the agent can accumulate findings
/// across multiple search iterations before producing a final summary.
/// </summary>
public sealed class NoteTool(ILogger<NoteTool> logger)
{
    private readonly List<NoteEntry> _notes = [];

    [Description("Save a research note with a topic label and content. Use this to record key findings from search results.")]
    public string SaveNote(
        [Description("A short topic label for the note")] string topic,
        [Description("The content of the note")] string content)
    {
        _notes.Add(new NoteEntry(topic, content, DateTime.UtcNow));
        logger.LogInformation("Note saved: \"{Topic}\" ({Length} chars)", topic, content.Length);
        return $"Note saved under topic \"{topic}\". You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes. Returns notes grouped by topic.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var grouped = _notes
            .GroupBy(n => n.Topic)
            .Select(g => $"## {g.Key}\n{string.Join("\n", g.Select(n => $"- {n.Content}"))}")
            .ToList();

        logger.LogInformation("Retrieved {Count} note(s) across {Groups} topic(s)", _notes.Count, grouped.Count);
        return string.Join("\n\n", grouped);
    }

    private sealed record NoteEntry(string Topic, string Content, DateTime Timestamp);
}

