using System.ClientModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent;

// --- Configuration -----------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- DI container ------------------------------------------------------------
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddHttpClient();
services.AddSingleton<WebSearchTool>();
services.AddSingleton<NoteTool>();

services.AddChatClient(builder =>
    builder.UseOpenAIChatClient(modelId, new OpenAIClient(new ApiKeyCredential(apiKey))));

var provider = services.BuildServiceProvider();

// --- Tools -------------------------------------------------------------------
var searchTool = provider.GetRequiredService<WebSearchTool>();
var noteTool = provider.GetRequiredService<NoteTool>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(searchTool.SearchWebAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
};

// --- Agent -------------------------------------------------------------------
var chatClient = provider.GetRequiredService<IChatClient>();
var loggerFactory = provider.GetRequiredService<ILoggerFactory>();

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI research assistant that searches the web, takes notes, and summarizes findings.",
    instructions: """
        You are a thorough research assistant. When given a topic:
        1. Search the web for relevant information using multiple targeted queries.
        2. Save key findings as notes using the note-taking tool, organized by sub-topic.
        3. After gathering enough information, retrieve your notes and produce a well-structured
           summary with an introduction, key findings (with source references), and a conclusion.
        Be factual, cite sources, and clearly distinguish established facts from speculation.
        """,
    tools: tools,
    loggerFactory: loggerFactory);

// --- Interactive loop --------------------------------------------------------
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════════════════════╗");
Console.WriteLine("║           🔍  Research Agent  (type 'exit' to quit) ║");
Console.WriteLine("╚══════════════════════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Green;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var input = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(input) || input.Equals("exit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    var session = await agent.CreateSessionAsync();

    var runOptions = new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    });

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching — this may take a moment...\n");
    Console.ResetColor();

    try
    {
        await foreach (var update in agent.RunStreamingAsync(input, session, runOptions))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine("\n");
}

